module top_module(
    input [7:0] binary,
    output [11:0] bcd
);reg [3:0] hundreds_digit;
reg [3:0] digit2;
reg [3:0] digit3;

always @ (binary) begin
    if (binary >= 100) begin
        hundreds_digit = binary / 100;
        digit2 = (binary % 100) / 10;
        digit3 = binary % 10;
    end else if (binary >= 10) begin
        hundreds_digit = 0;
        digit2 = binary / 10;
        digit3 = binary % 10;
    end else begin
        hundreds_digit = 0;
        digit2 = 0;
        digit3 = binary;
    end
end

assign bcd = {hundreds_digit, digit2, digit3};

endmodule
